// Parse the Gemini API response and merge with document data
const geminiResponse = $input.first().json;
const docData = $('Extract Text from Document').first().json;

let metadata = {};
try {
  const text = geminiResponse.candidates[0].content.parts[0].text;
  // Remove markdown code fences if present
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  metadata = JSON.parse(cleaned);
} catch (e) {
  metadata = {
    document_type: 'unknown',
    effective_date: null,
    expiration_date: null,
    parties: [],
    jurisdiction: 'unknown',
    key_clauses: [],
    monetary_amounts: [],
    compliance_requirements: [],
    risk_flags: ['metadata_extraction_failed'],
    summary: 'Failed to extract metadata from document.'
  };
}

// Generate a simple text embedding placeholder
// In production, use Gemini embedding API
const embeddingText = `${metadata.document_type} ${metadata.summary} ${(metadata.key_clauses || []).map(c => c.clause_name).join(' ')}`;

return [{
  json: {
    ...docData,
    metadata: metadata,
    embedding_text: embeddingText,
    processing_status: 'metadata_extracted'
  }
}];

// Build knowledge graph edges from extracted metadata
const docData = $('Parse Gemini Response').first().json;
const metadata = docData.metadata;
const edges = [];

// Entity <-> Document edge
edges.push({
  source: docData.entity_id,
  target: docData.document_id,
  relationship: 'owns_document',
  properties: {
    document_type: metadata.document_type,
    uploaded_at: docData.uploaded_at
  }
});

// Document <-> Jurisdiction edge
if (metadata.jurisdiction && metadata.jurisdiction !== 'unknown') {
  edges.push({
    source: docData.document_id,
    target: `jurisdiction_${metadata.jurisdiction.toLowerCase().replace(/\s+/g, '_')}`,
    relationship: 'governed_by',
    properties: { jurisdiction: metadata.jurisdiction }
  });
}

// Document <-> Parties edges
for (const party of (metadata.parties || [])) {
  edges.push({
    source: docData.document_id,
    target: `party_${party.toLowerCase().replace(/\s+/g, '_')}`,
    relationship: 'involves_party',
    properties: { party_name: party }
  });
}

// Document <-> Compliance Requirements edges
for (const req of (metadata.compliance_requirements || [])) {
  edges.push({
    source: docData.document_id,
    target: `req_${req.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 50)}`,
    relationship: 'requires_compliance',
    properties: { requirement: req }
  });
}

return [{
  json: {
    document_id: docData.document_id,
    entity_id: docData.entity_id,
    filename: docData.filename,
    metadata: metadata,
    knowledge_graph_edges: edges,
    edge_count: edges.length,
    processing_status: 'complete'
  }
}];
